var adElement = "#ap_iframe";
var authlevel = 0;

$(function() {
        $(window).load(updateAds);
        $(window).resize(updateAds);
        $('body').on('DOMNodeInserted', adElement, updateAds);
        $('body').on('DOMNodeRemoved', adElement, updateAds);
});

function updateAds() {
        var height = $(window).height() -
                $(adElement).height();
        var hideAd = height <= 250;
        if (hideAd) height = $(window).height();
        $(adElement)[hideAd ? "hide" : "show"]();
        $("#content").height(height);
}
class Bonzi {
        constructor(id, userPublic) {

                // ========================================================================
                // VARIABLES/CONSTANTS
                // ========================================================================
                this.userPublic = userPublic || {
                        name: "BonziBUDDY",
                        color: "purple",
                        speed: 0.575,
                        pitch: 50,
                        voice: "en-us"
                };
                this.color = this.userPublic.color;
                this.colorPrev;
                this.data = window.BonziData;

                this.drag = false;
                this.dragged = false;

                this.eventQueue = [];

                this.eventRun = true;
                this.event = null;

                this.willCancel = false;

                this.run = true;

                this.mute = false;

                this.eventTypeToFunc = {
                        "anim": "updateAnim",
                        "html": "updateText",
                        "text": "updateText",
                        "idle": "updateIdle",
                        "add_random": "updateRandom"
                };

                // ========================================================================
                // ASSIGN ID
                // http://stackoverflow.com/a/105074
                // ========================================================================

                if (typeof id == "undefined") {
                        this.id = s4() + s4();
                } else this.id = id;

                this.rng = new Math.seedrandom((this.seed || this.id) || Math.random());

                // ========================================================================
                // HTML POPULATION
                // ========================================================================
                this.selContainer = "#content";
                this.$container = $(this.selContainer);
                                
                this.$container.append(`
                        <div id='bonzi_${this.id}' class='bonzi'>
                                <div class='bonzi_name'> style='display: none;'</div>
                                        <div class='bonzi_placeholder' style='display: none;'></div>
                                <div style='display:none' class='bubble'>
                                        <p class='bubble-content'></p>
                                </div>
                        </div>
                `);

                this.selElement = "#bonzi_" + this.id;
                this.selDialog = this.selElement + " > .bubble";
                this.selDialogCont = this.selElement + " > .bubble > p";
                this.selNametag = this.selElement + " > .bonzi_name";

                this.selCanvas = this.selElement + " > .bonzi_placeholder";
                $(this.selCanvas)
                        .width(this.data.size.x)
                        .height(this.data.size.y);

                this.$element   = $(this.selElement);
                this.$canvas    = $(this.selCanvas);
                this.$dialog    = $(this.selDialog);
                this.$dialogCont        = $(this.selDialogCont);
                this.$nametag   = $(this.selNametag);

                this.updateName();

                $.data(this.$element[0], "parent", this);

                this.updateSprite(true);

                // ========================================================================
                // EVENTS
                // ========================================================================
                this.generate_event = function(a, b, c) { // Selector, event, function
                        a[b](e => { this[c](e); });
                };

                this.generate_event(
                        this.$canvas,
                        "mousedown",
                        "mousedown"
                );
                
                this.generate_event(
                        $(window),
                        "mousemove",
                        "mousemove"
                );
                
                this.generate_event(
                        $(window),
                        "mouseup",
                        "mouseup"
                );

                var coords = this.maxCoords();
                this.x = coords.x * this.rng();
                this.y = coords.y * this.rng();
                this.move();
                
                // ========================================================================
                // MENU
                // ========================================================================


                // ========================================================================
                // UPDATE LOOP
                // ========================================================================

                this.needsUpdate = false;

                $("#bonzi_chat_messages").append(`<p>${this.userPublic.name} joined the room</p>`)
                //$("#bonzi_chat_online").append(`<div class="${this.id}">${this.userPublic.name}</div>`)
                this.runSingleEvent([{
                        type: "anim",
                        anim: "surf_intro",
                        ticks: 30
                }]);
                
                let chatsound = new Audio("../dooropen.wav");
                chatsound.play();
                
                var bonzi = this;
                
                $.contextMenu({
                        selector: `.${this.id}`,
                        build: ($trigger, e) => {
                                
                let menu = {
                                        items: {
                                                "cancel": {
                                                        name: "Cancel / Interrupt",
                                                        callback: () => { this.cancel(); }
                                                },
                                                "mute": {
                                                        name: () => this.mute ? "Unmute" : "Mute",
                                                        callback: () => {
                                                                this.cancel();
                                                                this.mute = !this.mute;
                                                        }
                                                },
                                                "call": {
                                                        name: "Call this User",
                                                        callback: () => {  
                                                                $("#bonzi_chat_text").val("Hey, "+this.userPublic.name+"! ")
                                                        }
                                                },
                                        } 
                                };
                                

                                if (authlevel >= 0.5 && authlevel <= 1) {
                    menu.items.mod = {
                        name: "YouTuber CMDs",
                        items: {
                                                "youtuber": {
                                                        name: "Youtoober",
                                                        callback: () => {  
                                                                $("#bonzi_chat_text").val("Hey, "+this.userPublic.name+"! Give me your youtube channel NOW! ")
                                                                }
                                                        },
                                                }
                                        };
                                } else if (authlevel >= 1) {
                    menu.items.mod = {
                        name: "Funny Mod Menu",
                        items: {
                            kick: {
                                name: "Kick",
                                callback: () => {
                                    socket.emit("command", { list: ["kick", bonzi.id] });
                                                                }
                                                        },
                            ban: {
                                name: "Ban",
                                callback: () => {
                                    socket.emit("command", { list: ["ban", bonzi.id] });
                                                                }
                                                        },
                                                }
                                        };
                                }
                                return menu;
                        },
                        animation: {
                                duration: 1,
                                show: 'fadeIn',
                                hide: 'fadeOut'
                        }
                });
        }

        eventMake(list) {
                return {
                        list: list,
                        index: 0,
                        timer: 0,
                        cur: function() { return this.list[this.index] }
                };
        }

        mousedown(e) {
                if (e.which == 1) {
                        this.drag = true;
                        this.dragged = false;
                        this.drag_start = {
                                x: e.pageX - this.x,
                                y: e.pageY - this.y
                        };
                }
        }

        mousemove(e) {
                if (this.drag) {
                        this.move(
                                e.pageX - this.drag_start.x,
                                e.pageY - this.drag_start.y
                        );
                        this.dragged = true;
                }
        }

        move(x, y) {
                if (arguments.length !== 0) {
                        this.x = x;
                        this.y = y;
                }
                var max = this.maxCoords();
                this.x = Math.min(
                        Math.max(0, this.x),
                        max.x
                );
                this.y = Math.min(
                        Math.max(0, this.y),
                        max.y
                );
                this.$element.css({
                        "marginLeft": this.x,
                        "marginTop": this.y
                });

                this.sprite.x = this.x;
                this.sprite.y = this.y;
                BonziHandler.needsUpdate = true;
                this.updateDialog();
        }

        mouseup(e) {
                if (!this.dragged && this.drag)
                        this.cancel();

                this.drag = false;
                this.dragged = false;
        }

        runSingleEvent(list) {
                if (!this.mute)
                        this.eventQueue.push(this.eventMake(list));
        }

        clearDialog() {
                this.$dialog.fadeOut(150);
        }

        cancel() {
                this.clearDialog();
                this.stopSpeaking();
                this.eventQueue = [this.eventMake([{ type: "idle" }])];
        }

        retry() {
                this.clearDialog();
                this.event.timer = 0;
        }

        stopSpeaking() {
                this.goingToSpeak = false;
                try {
                        this.voiceSource.stop();
                } catch(e) {}
        }

        cancelQueue() {
                this.willCancel = true;
        }


        updateAnim() {
                if (this.event.timer === 0)
                        this.sprite.gotoAndPlay(this.event.cur().anim);
                this.event.timer++;
                BonziHandler.needsUpdate = true;
                if (this.event.timer >= this.event.cur().ticks)
                        this.eventNext();
        }

        updateText() {
                if (this.event.timer === 0) {
                        this.$dialogCont.html("");
                        this.$dialog.fadeIn(150);
                        this.event.timer = 1;
                        this.talk(
                                this.event.cur().text,
                                this.event.cur().say,
                                true
                        );
                }
                
                if (this.$dialog.css("display") == "none")
                        this.eventNext();
        }

        updateIdle() {
                var goNext =
                        (this.sprite.currentAnimation == "idle") &&
                        (this.event.timer === 0);

                goNext = goNext ||
                        this.data.pass_idle.indexOf(
                                this.sprite.currentAnimation
                        ) != -1;

                if (goNext)
                        this.eventNext();
                else {
                        if (this.event.timer === 0) {
                                this.tmp_idle_start =
                                        this.data.to_idle[this.sprite.currentAnimation];
                                this.sprite.gotoAndPlay(this.tmp_idle_start);
                                this.event.timer = 1;
                        }
                        
                        if (this.tmp_idle_start != this.sprite.currentAnimation)
                                if (this.sprite.currentAnimation == "idle")
                                        this.eventNext();

                        BonziHandler.needsUpdate = true;
                }
        }

        updateRandom() {
                var add = this.event.cur().add;
                var index = Math.floor(add.length * this.rng());

                var e = this.eventMake(add[index]);
                this.eventNext();
                this.eventQueue.unshift(e);
        }

        update() {
                
                        if (this.color.startsWith("http")) {
                            //Set canvas bg to the crosscolor as easel.js itself cant handle cors
                            this.$canvas.css("background-image", 'url("' + this.color + '")');
                            this.$canvas.css("background-position-x", -Math.floor(this.sprite.currentFrame % 17) * this.data.size.x + 'px');
                            this.$canvas.css("background-position-y", -Math.floor(this.sprite.currentFrame / 17) * this.data.size.y + 'px');
                        } else this.$canvas.css("background-image", 'none');
                if (!this.run) return; 
                // ========================================================================
                // EVENTS
                // "the fun part"
                // ========================================================================

                if ((this.eventQueue.length !== 0) && (this.eventQueue[0].index >= this.eventQueue[0].list.length))
                        this.eventQueue.splice(0,1);

                this.event = this.eventQueue[0];

                if ((this.eventQueue.length !== 0) && this.eventRun) {
                        var eventType = this.event.cur().type;
                        try {
                                this[this.eventTypeToFunc[eventType]]();
                        } catch(e) { this.event.index++; }
                }

                if (this.willCancel) {
                        this.cancel();
                        this.willCancel = false;
                }

                if (this.needsUpdate) {
                        this.stage.update();
                        this.needsUpdate = false;
                }
        }

        eventNext() {
                this.event.timer = 0;
                this.event.index += 1;
        }

        talk(text, say, allowHtml) {
                allowHtml = allowHtml || false;
                text = replaceAll(text, "{NAME}", this.userPublic.name);
                text = replaceAll(text, "{COLOR}", this.color);
                if (typeof say !== "undefined") {
                        say = "[[_^_en]] " + replaceAll(say, "{NAME}", this.userPublic.name);
                        say = "[[_^_en]] " + replaceAll(say, "{COLOR}", this.color);
                } else {
                        say = "[[_^_en]] " + text.replaceAll("&gt;", "").replaceAll(",",", [[_^_en]]").replaceAll(".", ". [[_^_en]]").replaceAll("?", "? [[_^_en]]").replaceAll("!", "! [[_^_en]]").replaceAll(":", ": [[_^_en]]").replaceAll(";", "; [[_^_en]]");
                }

                //text = linkify(text);
                // temporary disable until we find a fix
                var greentext = 
                        (text.substring(0, 4) == "&gt;") ||
                        (text[0] == ">");

                this.$dialogCont
                        [allowHtml ? "html" : "text"](text)
                        [greentext ? "addClass" : "removeClass"]("bubble_greentext")
                        .css("display", "block");

                this.stopSpeaking();

                this.goingToSpeak = true;
                $("#bonzi_chat_messages").append(`<p>${this.userPublic.name} said: ${text}</p>`)
                speak.play(say, {
                        "pitch": this.userPublic.pitch,
                        "speed": this.userPublic.speed,
                        "amplitude": 50,
                }, () => { // onended
                        this.clearDialog()
                }, (source) => {
                        if (!this.goingToSpeak) source.stop();
                        this.voiceSource = source;
                });
                
                // Getting the height of the document
                var n = $('#bonzi_chat_messages').height();
                
                // Animating the scroll to the bottom
                $('#bonzi_chat_messages').animate({ scrollTop: 100000 }, 150);
                let chatsound = new Audio("../notify.ogg");
                chatsound.play();
        }

        joke() { this.runSingleEvent(this.data.event_list_joke); }

        fact() { this.runSingleEvent(this.data.event_list_fact); }

        exit(callback) {
                if (!this.leaving) {
                        
                        $("#bonzi_chat_messages").append(`<p>${this.userPublic.name} left the room</p>`);
                        let chatsound = new Audio("../doorslam.wav");
                        chatsound.play();
                        this.leaving = true;
                }
                this.runSingleEvent([{
                        type: "anim",
                        anim: "surf_away",
                        ticks: 30
                }]);
                setTimeout(callback, 2000);
                
                $(`.${this.id}`).remove()
        }

        deconstruct() {
                this.stopSpeaking();
                BonziHandler.stage.removeChild(this.sprite);
                this.run = false;
                this.$element.remove();
        }

  updateName() { 
    if (this.mute) return; 
    let name = this.userPublic.name;
    if (name.toLowerCase().includes("bonziuser")) {
        name = "long boba";
    }
    $(`.${this.id}`).remove(); 
    $("#bonzi_chat_online").append(`<div class="${this.id}">${name}</div>`); 
    this.$nametag.text(name); 
}
        youtube(vid) {
                if (!this.mute) {
                        var tag = "iframe";
                        $("#bonzi_chat_messages").append(`${this.userPublic.name}: 
                                        <${tag} type="text/html" width="173" height="173" 
                                        src="https://www.youtube.com/embed/${vid}" 
                                        style="width:173px;height:173px"
                                        frameborder="0"
                                        allowfullscreen="allowfullscreen"
                                        mozallowfullscreen="mozallowfullscreen"
                                        msallowfullscreen="msallowfullscreen"
                                        oallowfullscreen="oallowfullscreen"
                                        webkitallowfullscreen="webkitallowfullscreen"
                                        ></${tag}>
                                <br>`)
                }
        }

        backflip(swag) {
                var event = [{
                        type: "anim",
                        anim: "backflip",
                        ticks: 15
                }];
                if (swag) {
                        event.push({
                                type: "anim",
                                anim: "cool_fwd",
                                ticks: 30
                        });
                        event.push({
                                type: "idle"
                        });
                }
                this.runSingleEvent(event);
        }

        updateDialog() {
        }

        maxCoords() {
                return {
                        x: this.$container.width() - this.data.size.x,
                        y: this.$container.height() - this.data.size.y - $("#chat_bar").height()
                };
        }

        asshole(target) {
                this.runSingleEvent(
                        [{
                                type: "text",
                                text: "Hey, " + target + "!"
                        }, {
                                type: "text",
                                text: "You're a fucking asshole!",
                                say: "your a fucking asshole!"
                        }, {
                                type: "anim",
                                anim: "grin_fwd",
                                ticks: 15
                        }, {
                                type: "idle"
                        }]
                );
        }
        
        owo(target) {
                this.runSingleEvent(
                        [{
                                type: "text",
                                text: `*notices ${target}'s BonziBulge™*`,
                                say: `notices ${target}s bonzibulge`
                        }, {
                                type: "text",
                                text: "owo, wat dis?",
                                say: "oh woah, what diss?"
                        }]
                );
        }

        updateSprite(hide) {
                var stage = BonziHandler.stage;
                this.cancel();
                stage.removeChild(this.sprite);
                
                if (this.colorPrev != this.color) {
                        delete this.sprite;
            var d = { images: ["./img/bonzi/purple.png"], frames: BonziData.sprite.frames, animations: BonziData.sprite.animations }
            var shjeet = new createjs.SpriteSheet(d);
            this.sprite = new createjs.Sprite(shjeet, hide ? "gone" : "idle")
                }
                stage.addChild(this.sprite);
                this.move();
        }
}
