var undefined;
var hostname = isApp ? "bonkey.world" : window.location.hostname;
var socket = io("//" + hostname + ":" + window.location.port);

var usersPublic = {};
var bonzis = {};

var debug = true;

function loadTest() {
        $("#login_card").hide();
        $("#login_error").hide();
        $("#login_load").show();

        login();
}

function login() {
        socket.emit("login", {
                name: $("#login_name").val(),
                room: $("#login_room").val()
        });

        setup();
}

$(function() {
        $("#login_go").click(loadTest);

        $("#login_room").val(window.location.hash.slice(1));

        $("#login_name, #login_room").keypress(function(e) {
                if(e.which == 13) login();
        });

        socket.on("authlevel", function (a) {
                authlevel = a.level;
                console.log(a.level)
        });
        
        socket.on("ban", function(data) {
                $("#page_ban").show();
                $("#ban_reason").html(data.reason);
                $("#ban_end").html(new Date(data.end).toString());
        });

        socket.on("kick", function(data) {
                $("#page_kick").show();
                $("#kick_reason").html(data.reason);
                $("#bonzi_chat_window").hide();
        });

        socket.on("loginFail", function(data) {
                var errorText = {
                        "nameLength": "Name too long.",
                        "full": "Room is full.",
                        "nameMal": "Nice try. Why would anyone join a room named that anyway?",
                        "toomuch": "You have too many users assigned to your IP. Close some tabs.",
                };
                $("#login_card").show();
                $("#login_load").hide();
                $("#login_error")
                        .show()
                        .text(
                                "Error: " +
                                errorText[data.reason] +
                                " (" + data.reason + ")"
                        );
        });

        socket.on("disconnect", function(data) {
                errorFatal();
        });
});

function errorFatal() {
        if (($("#page_ban").css("display") == "none") || ($("#page_kick").css("display") == "none")) {
                $("#page_error").show();
        }
}

var chatTypingUsers = {};
var myGuid = null;
var myName = null;
function updateChatTypingDisplay() {
        var names = Object.values(chatTypingUsers);
        var el = $("#bonzi_chat_typing");
        if (el.length === 0) return;
        if (names.length === 0) {
                el.text("").hide();
        } else if (names.length === 1) {
                el.text(names[0] + " is typing...").show();
        } else if (names.length === 2) {
                el.text(names[0] + " and " + names[1] + " are typing...").show();
        } else {
                el.text(names.slice(0, -1).join(", ") + " and " + names[names.length - 1] + " are typing...").show();
        }
}

function setup() {
        $("#bonzi_chat_say").click(sendInput);

        $("#bonzi_chat_text").keypress(function(e) {
                if(e.which == 13) sendInput();
        });

        var typingTimeout;
        var isCurrentlyTyping = false;
        $("#bonzi_chat_text").on("input", function() {
                if ($(this).val().length > 0 && !isCurrentlyTyping) {
                        isCurrentlyTyping = true;
                        socket.emit("typing", { isTyping: true });
                        if (myGuid && myName) {
                                chatTypingUsers[myGuid] = myName + " (You)";
                                updateChatTypingDisplay();
                        }
                }
                clearTimeout(typingTimeout);
                typingTimeout = setTimeout(function() {
                        if (isCurrentlyTyping) {
                                isCurrentlyTyping = false;
                                socket.emit("typing", { isTyping: false });
                                if (myGuid) {
                                        delete chatTypingUsers[myGuid];
                                        updateChatTypingDisplay();
                                }
                        }
                }, 1500);
        });
        $("#bonzi_chat_text").on("keypress", function(e) {
                if (e.which == 13) {
                        clearTimeout(typingTimeout);
                        isCurrentlyTyping = false;
                        socket.emit("typing", { isTyping: false });
                        if (myGuid) {
                                delete chatTypingUsers[myGuid];
                                updateChatTypingDisplay();
                        }
                }
        });

        $("#bonzi_chat_clip").click(function() {
                $("#bonzi_chat_file").val("");
                $("#bonzi_chat_file").trigger("click");
        });
        $("#bonzi_chat_file").on("change", function() {
                var file = this.files && this.files[0];
                if (!file) return;
                if (file.size > 25 * 1024 * 1024) {
                        alert("File too large. Max 25 MB.");
                        return;
                }
                var btn = $("#bonzi_chat_clip");
                var prevHTML = btn.html();
                btn.prop("disabled", true).text("...");
                var fd = new FormData();
                fd.append("file", file);
                $.ajax({
                        url: "/upload",
                        type: "POST",
                        data: fd,
                        processData: false,
                        contentType: false
                }).done(function(resp) {
                        if (!resp || !resp.url || !resp.kind) {
                                alert("Upload failed.");
                                return;
                        }
                        socket.emit("command", { list: [resp.kind, resp.url] });
                }).fail(function(xhr) {
                        var msg = "Upload failed.";
                        try { msg = (xhr.responseJSON && xhr.responseJSON.error) || msg; } catch(e) {}
                        alert(msg);
                }).always(function() {
                        btn.prop("disabled", false).html(prevHTML);
                });
        });

        function _appendMedia(data, kind) {
                if (!data || !data.url) return;
                var pub = window.usersPublic ? window.usersPublic[data.guid] : null;
                var name = pub ? pub.name : "?";
                var safeUrl = String(data.url).replace(/"/g, "&quot;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
                var label, html;
                if (kind === "image") {
                        html = '<img src="' + safeUrl + '" style="max-width:280px;max-height:200px;display:block;margin-top:4px;" ' +
                                'onerror="this.outerHTML=&quot;<i>(image failed to load)</i>&quot;"/>';
                } else if (kind === "video") {
                        html = '<video src="' + safeUrl + '" controls preload="metadata" ' +
                                'style="max-width:300px;max-height:220px;display:block;margin-top:4px;background:#000;"></video>';
                } else if (kind === "audio") {
                        // No autoplay for audio
                        html = '<audio src="' + safeUrl + '" controls preload="metadata" ' +
                                'style="display:block;margin-top:4px;width:280px;"></audio>';
                } else {
                        return;
                }
                $("#bonzi_chat_messages").append('<p>' + name + ':<br>' + html + '</p>');
                $('#bonzi_chat_messages').animate({ scrollTop: 100000 }, 150);
        }

        socket.on("image", function(data) { _appendMedia(data, "image"); });
        socket.on("video", function(data) { _appendMedia(data, "video"); });
        socket.on("audio", function(data) { _appendMedia(data, "audio"); });

        socket.on("typing", function(data) {
                if (!data || !data.guid) return;
                var pub = window.usersPublic ? window.usersPublic[data.guid] : null;
                if (data.isTyping && pub) {
                        chatTypingUsers[data.guid] = pub.name;
                } else {
                        delete chatTypingUsers[data.guid];
                }
                updateChatTypingDisplay();
        });

        socket.on("room", function(data) {
                $("#room_owner")[data.isOwner ? "show" : "hide"]();
                $("#room_public")[data.isPublic ? "show" : "hide"]();
                $("#room_private")[!data.isPublic ? "show" : "hide"]();
                $(".room_id").text(data.room);
        });

        socket.on("updateAll", function(data) {
                $("#login_card").hide();
                $("#bonzi_chat_window").show();
                usersPublic = data.usersPublic;
                if (data.guid) {
                        myGuid = data.guid;
                        if (usersPublic[data.guid]) myName = usersPublic[data.guid].name;
                }
                usersUpdate();
                BonziHandler.bonzisCheck();
        });

        socket.on("update", function(data) {
                window.usersPublic[data.guid] = data.userPublic;
                usersUpdate();
                BonziHandler.bonzisCheck();
        });

        socket.on("talk", function(data) {
                var b = bonzis[data.guid];
                if (chatTypingUsers[data.guid]) {
                        delete chatTypingUsers[data.guid];
                        updateChatTypingDisplay();
                }
                b.cancel();
                b.runSingleEvent([{
                        type: "text",
                        text: data.text
                }]);
        });

        socket.on("joke", function(data) {
                var b = bonzis[data.guid];
                b.rng = new Math.seedrandom(data.rng);
                b.cancel();
                b.joke();
        });

        socket.on("youtube", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.youtube(data.vid);
        });

        socket.on("fact", function(data) {
                var b = bonzis[data.guid];
                b.rng = new Math.seedrandom(data.rng);
                b.cancel();
                b.fact();
        });

        socket.on("backflip", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.backflip(data.swag);
        });

        socket.on("asshole", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.asshole(data.target);
        });

        socket.on("owo", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.owo(data.target);
        });

        socket.on("triggered", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.runSingleEvent(b.data.event_list_triggered);
        });

        socket.on("linux", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.runSingleEvent(b.data.event_list_linux);
        });

        socket.on("pawn", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.runSingleEvent(b.data.event_list_pawn);
        });

        socket.on("bees", function(data) {
                var b = bonzis[data.guid];
                b.cancel();
                b.runSingleEvent(b.data.event_list_bees);
        });

        socket.on("vaporwave", function(data) {
                $("body").addClass("vaporwave");
        });

        socket.on("unvaporwave", function(data) {
                $("body").removeClass("vaporwave");
        });

        socket.on("leave", function(data) {
                var b = bonzis[data.guid];
                if (chatTypingUsers[data.guid]) {
                        delete chatTypingUsers[data.guid];
                        updateChatTypingDisplay();
                }
                if (typeof b != "undefined") {
                        b.exit((function(data) {
                                this.deconstruct();
                                delete bonzis[data.guid];
                                delete usersPublic[data.guid];
                                usersUpdate();
                        }).bind(b, data));
                }
        });
}

var usersAmt = 0;
var usersKeys = [];

function usersUpdate() {
        usersKeys = Object.keys(usersPublic);
        usersAmt = usersKeys.length;
}

function sendInput() {
        var text = $("#bonzi_chat_text").val();
        $("#bonzi_chat_text").val("");
        if (myGuid && chatTypingUsers[myGuid]) {
                delete chatTypingUsers[myGuid];
                updateChatTypingDisplay();
        }
        if (text.length > 0) {
                var youtube = youtubeParser(text);
                if (youtube) {
                        socket.emit("command", {
                                list: ["youtube", youtube]
                        });
                        return;
                } else if (text == "/?" || text == "/help") {
                        $("#bonzi_chat_messages").append(`<p><i>[System] <h4>List of available commands</h4><br>/joke - Tell a 'funny' joke.<br>/fact - Tell a well known fact.<br>/youtube &lt;video-id&gt; - Send a YouTube video.<br>/linux - I'd just like to interject for a moment.<br>/pawn - Hi, my name is BonziBUDDY.<br>/bees - Say the entire bee movie script.</i></p>`)
                } else if (text.substring(1,0) == "/") {
                        var list = text.substring(1).split(" ");
                        socket.emit("command", {
                                list: list
                        });
                } else {
                        socket.emit("talk", {
                                text: text
                        });
                }
        }
}
// http://stackoverflow.com/a/1781750

function touchHandler(event)
{
    var touches = event.changedTouches,
        first = touches[0],
        type = "";
    switch(event.type)
    {
        case "touchstart": type = "mousedown"; break;
        case "touchmove":  type = "mousemove"; break;        
        case "touchend":   type = "mouseup";   break;
        default:           return;
    }

    // initMouseEvent(type, canBubble, cancelable, view, clickCount, 
    //                screenX, screenY, clientX, clientY, ctrlKey, 
    //                altKey, shiftKey, metaKey, button, relatedTarget);

    var simulatedEvent = document.createEvent("MouseEvent");
    simulatedEvent.initMouseEvent(type, true, true, window, 1, 
                                  first.screenX, first.screenY, 
                                  first.clientX, first.clientY, false, 
                                  false, false, false, 0/*left*/, null);

    first.target.dispatchEvent(simulatedEvent);
    // event.preventDefault();
}

$(window).load(function(){
    document.addEventListener("touchstart", touchHandler, true);
    document.addEventListener("touchmove", touchHandler, true);
    document.addEventListener("touchend", touchHandler, true);
    document.addEventListener("touchcancel", touchHandler, true);    
});

